import{_ as a,c as e,o as s,a4 as i}from"./chunks/framework.BmdFiWrL.js";const g=JSON.parse('{"title":"How to Enable TSDB","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"en_US/guide/q15.md","filePath":"en_US/guide/q15.md","lastUpdated":1780234477000}'),t={name:"en_US/guide/q15.md"},n=i(`<h1 id="how-to-enable-tsdb" tabindex="-1">How to Enable TSDB <a class="header-anchor" href="#how-to-enable-tsdb" aria-label="Permalink to &quot;How to Enable TSDB&quot;">​</a></h1><p>TSDB is disabled by default. The Dashboard initializes the built-in VictoriaMetrics storage only when <code>tsdb.data_path</code> is configured.</p><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>After TSDB is enabled, the server detail page can query historical metric periods such as 1 day, 7 days, and 30 days. When TSDB is disabled, the frontend locks these historical periods.</p><p>Service monitoring history still reads from the database when TSDB is disabled. After TSDB is enabled, it reads from TSDB instead.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>Edit the Dashboard configuration file, usually <code>/opt/nezha/dashboard/data/config.yaml</code>, and add or update:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tsdb</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  data_path</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;data/tsdb&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  retention_days</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">30</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  min_free_disk_space_gb</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  max_memory_mb</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">256</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  write_buffer_size</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">512</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  write_buffer_flush_interval</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span></span></code></pre></div><p><code>data_path</code> can be relative or absolute. Relative paths are resolved from the Dashboard working directory. If this field is empty, TSDB is not enabled.</p><p>You can also enable it with an environment variable:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">NZ_TSDB_DATA_PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">data/tsdb</span></span></code></pre></div><p>Restart the Dashboard after changing the configuration.</p><h2 id="verify" tabindex="-1">Verify <a class="header-anchor" href="#verify" aria-label="Permalink to &quot;Verify&quot;">​</a></h2><p>Check the Dashboard log after restart:</p><ul><li><code>TSDB initialized successfully</code>: TSDB is enabled.</li><li><code>TSDB is disabled (tsdb.data_path not configured)</code>: <code>data_path</code> is not configured, so TSDB is still disabled.</li></ul><p>The frontend also reads <code>tsdb_enabled</code> from the system configuration API. If it is <code>false</code>, historical metric periods on the server detail page stay locked.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><p>After TSDB is enabled, the Dashboard drops the legacy <code>service_histories</code> database table. Existing service monitoring history is not automatically migrated to TSDB, so back up the database before enabling it.</p><p>TSDB uses local disk storage. Make sure the partition for <code>data_path</code> has enough free space, and adjust <code>retention_days</code>, <code>min_free_disk_space_gb</code>, and <code>max_memory_mb</code> according to your server count and retention needs.</p>`,19),o=[n];function d(l,r,h,p,c,k){return s(),e("div",null,o)}const u=a(t,[["render",d]]);export{g as __pageData,u as default};
